var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"최상층인데도 생체 반응이 감지되지 않는군요.","JPN":"最上層なのに生体反応が感知されませんね。","ENG":"I am on the top floor yet I sense no signs of life.","TWN":"最上層也沒有感應到生物反應。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"ですが……","ENG":"However…","TWN":"不過……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……침식파 반응은 아주 선명합니다.","JPN":"……侵食波反応は非常に鮮明です。","ENG":"…The Corruption Ray signatures are clearer than ever.","TWN":"……侵蝕波反應非常明顯。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 많이 지쳤구나. 동력이 얼마 남지 않았나 보네.","JPN":"フフッ、だいぶお疲れのようね。動力があまり残っていないのかしら。","ENG":"Heh. You must be pooped. I guess you don't have much juice left in you.","TWN":"呵呵～你累了嗎？動能似乎沒剩多少喔～"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"다시 만나서 반가워. 호라이즌. 널 기다리고 있었어.","JPN":"また会えて嬉しいわ、ホライズン。あなたを待っていたの。","ENG":"Nice to see you again, Horizon. I've been expecting you.","TWN":"真開心又見到你，地平線。我一直在等你呢～"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……셰나.","JPN":"……シェナ。","ENG":"…Shena.","TWN":"……世娜。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신들에게는 관심없습니다. 처음부터 윌버만 곱게 내놓으면 끝날 일이었습니다.","JPN":"あなたたちには興味ありません。最初からウィルバーさえ大人しく譲ってくれれば終わる話です。","ENG":"I have no business with you. This could have ended swiftly if you would have simply surrendered Wilbur to me.","TWN":"我的重點不是你們，一開始只要乖乖把韋爾伯交出來就沒事了。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"글쎄, 그런 것치고는 우리 연구 시설을 죄다 부수고 다니던걸?","JPN":"まあ、そんなことを言いながら、うちの研究施設を手当たり次第壊しまくっているじゃない。","ENG":"I don't know about that. I mean, you've been smashing all of our research centers!","TWN":"是這樣嗎？這有到需要把我們的研究設施全都毀掉的程度？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"거짓말이 서툰 거 아냐, 호라이즌?","JPN":"嘘が下手なんじゃない？　ホライズン。","ENG":"You're not a very good liar, are you Horizon?","TWN":"你很不擅長說謊呢，地平線。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 솔직하지 못한 점도 귀엽네.","JPN":"フフッ。素直じゃないところも可愛いわ。","ENG":"Heh. I even find your dishonesty just adorable.","TWN":"呵呵～不敢說實話的樣子也很可愛呢。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"네 탓이야, 호라이즌. 계속 그렇게 유혹하니까 가지고 놀고 싶어지잖아.","JPN":"あなたのせいよ、ホライズン。そうやってずっと誘惑してくるから遊んでみたくなるじゃない。","ENG":"This is all your fault, Horizon. You tempting me like that makes me want to play with you.","TWN":"都是你不好～誰叫你一直誘惑我，害我越想逗著你玩。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그렇지 않았으면, 저 얼빠진 인간 따위 진즉 내 손으로 죽여 버렸을 텐데.","JPN":"そうでなければ、あんなクズ人間なんかさっさと私の手で殺してやったのに。","ENG":"Otherwise, I would have killed that fool myself a long time ago.","TWN":"否則我早就親手處理掉那個愚蠢的人類了。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신도 학회 소속 아니었습니까. 학회에서 그를 더 이상 비호하지 않기로 했나 보군요.","JPN":"あなたも学会所属だったと思いますが。学会では彼をこれ以上庇護しないことにしたのですね。","ENG":"But aren't you an associate of the Society? I take it that the Society has decided to no longer protect the man.","TWN":"你不也是學會的人嗎？看來是學會下令不再保護他的安危嗎？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"뭐, 감찰관까지 행차하셨으니 당연한 이야기지. 옥상으로 간 바보는 아직 상황 파악이 안 됐지만.","JPN":"まあ、監察官様までお出ましになったんだから当然の話よ。屋上に行ったあのバカはまだ状況が把握できていないようだけど。","ENG":"Well, duh. They even sent an inspector. That fool running off to the rooftop still has no idea though.","TWN":"都已經派監察委員來到這裡，這不是很明顯嗎？只是屋頂上的那個傻瓜還搞不清楚狀況～"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하지만 오해하지 마. 일단 신세는 지고 있어도 <color=#ffd34c>우리</color>한테는 학회의 철칙보다 더 중요한 게 있거든.","JPN":"でも誤解しないで。一応お世話になってはいるけど<color=#ffd34c>私たち</color>には学会の鉄則よりもっと重要なものがあるから。","ENG":"Don't let it fool you though. We may be hanging our hats with the Society for now, but there's something more important that the Society's rules for <color=#ffd34c>us</color>.","TWN":"不過你別誤會，雖然暫時依附在學會底下，但對<color=#ffd34c>我們</color>而言，有比學會的指令更重要的東西。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"멘탈 프린팅 기술입니까?","JPN":"メンタル・プリンティング技術ですか？","ENG":"You mean the Mental Printing technology?","TWN":"智力複印技術嗎？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};